import React, { useRef, useEffect, useMemo, useState, Suspense } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { useGLTF, OrbitControls, Environment, ContactShadows } from "@react-three/drei";
import * as THREE from "three";
import PhoneFallback from "./PhoneFallback";

// The mesh node name for the iPhone screen in scene.glb (adrianhajdin/iphone)
const SCREEN_NODE = "xXDHkMplTIDAXLN";

function hasWebGL() {
  try {
    const c = document.createElement("canvas");
    return !!(c.getContext("webgl") || c.getContext("experimental-webgl"));
  } catch {
    return false;
  }
}

// Sports tech platform screen texture – no app name shown
function makeBenchmarkTexture() {
  const canvas = document.createElement("canvas");
  canvas.width = 512;
  canvas.height = 1024;
  const ctx = canvas.getContext("2d");

  // Deep dark green-black bg
  const bg = ctx.createLinearGradient(0, 0, 0, 1024);
  bg.addColorStop(0, "#060b06");
  bg.addColorStop(1, "#0a130a");
  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, 512, 1024);

  // Green status bar
  ctx.fillStyle = "#3DDC84";
  ctx.fillRect(0, 0, 512, 36);

  // Icon glow
  const glow = ctx.createRadialGradient(256, 250, 10, 256, 250, 110);
  glow.addColorStop(0, "rgba(61,220,132,0.25)");
  glow.addColorStop(1, "rgba(61,220,132,0)");
  ctx.fillStyle = glow;
  ctx.fillRect(156, 150, 200, 200);

  // Icon rounded rect (Android green)
  ctx.fillStyle = "rgba(61,220,132,0.15)";
  ctx.strokeStyle = "rgba(61,220,132,0.5)";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.roundRect(196, 190, 120, 120, 28);
  ctx.fill();
  ctx.stroke();

  // Android icon (simplified)
  ctx.font = "56px Arial";
  ctx.textAlign = "center";
  ctx.fillText("🤸", 256, 270);

  // Title — generic "Sports Tech"
  ctx.fillStyle = "#3DDC84";
  ctx.font = "bold 30px Arial";
  ctx.letterSpacing = "3px";
  ctx.fillText("SPORTS TECH", 256, 358);

  ctx.fillStyle = "rgba(61,220,132,0.5)";
  ctx.font = "16px Arial";
  ctx.letterSpacing = "1px";
  ctx.fillText("Athlete Performance", 256, 392);

  // Divider
  ctx.strokeStyle = "rgba(61,220,132,0.2)";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(56, 428);
  ctx.lineTo(456, 428);
  ctx.stroke();

  // Store badges
  ctx.fillStyle = "rgba(61,220,132,0.06)";
  ctx.strokeStyle = "rgba(61,220,132,0.15)";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.roundRect(48, 448, 190, 52, 10);
  ctx.fill();
  ctx.stroke();
  ctx.beginPath();
  ctx.roundRect(274, 448, 190, 52, 10);
  ctx.fill();
  ctx.stroke();

  ctx.fillStyle = "#ffffff";
  ctx.font = "16px Arial";
  ctx.letterSpacing = "0px";
  ctx.fillText("🍎  App Store", 143, 480);
  ctx.fillText("▶  Play Store", 369, 480);

  // Stats
  ctx.fillStyle = "rgba(61,220,132,0.06)";
  ctx.strokeStyle = "rgba(61,220,132,0.15)";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.roundRect(36, 524, 200, 88, 12);
  ctx.fill();
  ctx.stroke();
  ctx.beginPath();
  ctx.roundRect(276, 524, 200, 88, 12);
  ctx.fill();
  ctx.stroke();

  ctx.fillStyle = "#3DDC84";
  ctx.font = "bold 28px Arial";
  ctx.fillText("< 1s", 136, 568);
  ctx.fillText("30%", 376, 568);
  ctx.fillStyle = "rgba(196,207,222,0.6)";
  ctx.font = "13px Arial";
  ctx.fillText("Load Time", 136, 592);
  ctx.fillText("Fewer API calls", 376, 592);

  // Tech pills
  const pills = ["React Native", "Django", "AWS", "Docker"];
  pills.forEach((label, i) => {
    const x = (i % 2) * 220 + 70;
    const y = 648 + Math.floor(i / 2) * 56;
    ctx.fillStyle = "rgba(61,220,132,0.08)";
    ctx.strokeStyle = "rgba(61,220,132,0.25)";
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.roundRect(x, y, 160, 36, 18);
    ctx.fill();
    ctx.stroke();
    ctx.fillStyle = "#3DDC84";
    ctx.font = "13px Arial";
    ctx.fillText(label, x + 80, y + 23);
  });

  // Bottom nav bar
  ctx.fillStyle = "rgba(61,220,132,0.05)";
  ctx.fillRect(0, 944, 512, 80);
  const navIcons = ["🏠", "📊", "🎯", "👤"];
  navIcons.forEach((ic, i) => {
    ctx.font = "22px Arial";
    ctx.fillText(ic, 64 + i * 128, 990);
  });

  return new THREE.CanvasTexture(canvas);
}

// Video texture hook – loads numa_mockup.mp4 as a Three.js VideoTexture
function useVideoTexture() {
  const [texture, setTexture] = useState(null);
  const videoRef = useRef(null);

  useEffect(() => {
    const video = document.createElement("video");
    video.src = "/videos/numa_mockup.mp4";
    video.muted = true;
    video.loop = true;
    video.playsInline = true;
    video.crossOrigin = "anonymous";
    videoRef.current = video;

    video.addEventListener("canplay", () => {
      const vt = new THREE.VideoTexture(video);
      vt.minFilter = THREE.LinearFilter;
      vt.magFilter = THREE.LinearFilter;
      setTexture(vt);
      video.play().catch(() => {});
    });

    video.load();
    return () => {
      video.pause();
      video.src = "";
    };
  }, []);

  return texture;
}

// The real iPhone 15 Pro model component
function IPhoneModel({ screenTexture }) {
  const { scene, nodes } = useGLTF("/models/iphone.glb");
  const groupRef = useRef();

  // Very gentle floating animation
  useFrame((state) => {
    if (groupRef.current) {
      groupRef.current.position.y =
        Math.sin(state.clock.elapsedTime * 0.6) * 0.04;
    }
  });

  // Apply screen texture whenever it changes
  useEffect(() => {
    if (!nodes) return;
    const screenMesh = nodes[SCREEN_NODE];
    if (screenMesh && screenTexture) {
      screenMesh.material = screenMesh.material.clone();
      screenMesh.material.map = screenTexture;
      screenMesh.material.roughness = 0;
      screenMesh.material.needsUpdate = true;
    }
  }, [nodes, screenTexture]);

  return (
    <group ref={groupRef}>
      <primitive
        object={scene}
        scale={[15, 15, 15]}
        position={[0, -0.8, 0]}
        rotation={[0, Math.PI / 6, 0]}
      />
    </group>
  );
}

// Preload so it starts fetching immediately on mount
useGLTF.preload("/models/iphone.glb");

function Scene({ activeApp }) {
  const benchmarkTexture = useMemo(() => makeBenchmarkTexture(), []);
  const videoTexture = useVideoTexture();

  const screenTexture =
    activeApp === "benchmark"
      ? benchmarkTexture
      : videoTexture;

  return (
    <>
      {/* Environment map for metallic reflections — makes the titanium finish look real */}
      <Environment preset="city" />

      {/* Key light — slightly warm */}
      <directionalLight
        position={[5, 8, 5]}
        intensity={2.5}
        color="#fff8f0"
        castShadow
      />
      {/* Green accent rim light from below-right — ties to designColor */}
      <pointLight
        position={[3, -3, 3]}
        intensity={1.2}
        color="#3DDC84"
      />
      {/* Cool fill from the left */}
      <pointLight
        position={[-6, 4, 2]}
        intensity={0.8}
        color="#c4cfde"
      />
      {/* Subtle ambient */}
      <ambientLight intensity={0.25} />

      <IPhoneModel screenTexture={screenTexture} />

      {/* Soft shadow under the phone */}
      <ContactShadows
        position={[0, -2.2, 0]}
        opacity={0.4}
        scale={8}
        blur={2.5}
        far={3}
        color="#000000"
      />

      <OrbitControls
        target={[0, -0.8, 0]}
        enableZoom={false}
        enablePan={false}
        minPolarAngle={Math.PI / 3}
        maxPolarAngle={Math.PI / 1.8}
        autoRotate
        autoRotateSpeed={1.2}
      />
    </>
  );
}

class WebGLErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }
  static getDerivedStateFromError() {
    return { hasError: true };
  }
  render() {
    if (this.state.hasError)
      return <PhoneFallback activeApp={this.props.activeApp} />;
    return this.props.children;
  }
}

const Phone3D = ({ activeApp = "meditation" }) => {
  if (!hasWebGL()) {
    return <PhoneFallback activeApp={activeApp} />;
  }

  return (
    <WebGLErrorBoundary activeApp={activeApp}>
      <Canvas
        style={{ width: "100%", height: "100%" }}
        dpr={[1, 2]}
        gl={{
          antialias: true,
          powerPreference: "high-performance",
          alpha: true,
        }}
        camera={{ position: [0, 0, 4], fov: 40 }}
        shadows
      >
        <Suspense fallback={null}>
          <Scene activeApp={activeApp} />
        </Suspense>
      </Canvas>
    </WebGLErrorBoundary>
  );
};

export default Phone3D;
